func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestAssignIdx := -1
		minDelta := 1e18
		for ii := 0; ii <= dispatch.AssignsLen; ii++ {
			if ii == MAXASSIGNS {
				break
			}
			savedCost := dispatch.Assigns[ii].Cost
			if savedCost < 0 {
				continue
			}
			added := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if !added {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				delta := newCost - savedCost
				if delta < minDelta {
					minDelta = delta
					bestAssignIdx = ii
				}
			}
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}
		targetIdx := bestAssignIdx
		if targetIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
				targetIdx = dispatch.AssignsLen
				dispatch.AssignsLen++
			} else {
				for ii := 0; ii < MAXASSIGNS; ii++ {
					ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
					if ok {
						dispatch.Assigns[ii].GenRoute()
						targetIdx = ii
						break
					}
				}
			}
		}
		if targetIdx >= 0 && targetIdx < MAXASSIGNS {
			dispatch.Assigns[targetIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[targetIdx].GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

