Greedy insertion with cost delta evaluation and randomized assign ordering, using backup assign creation for unplaceable orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	activeIndices := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		activeIndices = append(activeIndices, i)
	}
	for i := 0; i < len(activeIndices); i++ {
		j := i + rand.Intn(len(activeIndices)-i)
		activeIndices[i], activeIndices[j] = activeIndices[j], activeIndices[i]
	}

	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		bestAssignIdx := -1
		bestDelta := 0.0
		bestFeasible := false
		shipID := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		candidateIndices := make([]int, len(activeIndices))
		copy(candidateIndices, activeIndices)

		for _, idx := range candidateIndices {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if !bestFeasible || delta < bestDelta {
						bestDelta = delta
						bestAssignIdx = idx
						bestFeasible = true
					}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		if bestFeasible {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
			continue
		}

		if dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[newIdx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					dispatch.AssignsLen++
					activeIndices = append(activeIndices, newIdx)
					continue
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}

		fallbackOk := false
		for i := 0; i < dispatch.AssignsLen && !fallbackOk; i++ {
			assign := &dispatch.Assigns[i]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					fallbackOk = true
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}
		if !fallbackOk && dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[newIdx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					dispatch.AssignsLen++
					activeIndices = append(activeIndices, newIdx)
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

